sys_script_email.script:
(function runMailScript( current,  template, email, email_action, event) {

	//parse JSON data and format HTML for the email notification, we had to use this email script in order to send multi value data through an event
	var obj = JSON.parse(event.parm1);
	// DFCT0010708 - 2
	var task_url = '';
	var gr_Task = new GlideRecord('x_153465_discovert_route_task_instance');
	if(gr_Task.get(obj.id)){
		task_url = new x_153465_discovert.tasker_User_Form_Preferences().getEmailUrl(gr_Task);
			email.setSubject(gr_Task.getDisplayValue("task_name") + gs.getMessage(', is in an Acceptance Overdue state'));
	}
	template.print("<p><span style='font-family: georgia, palatino; font-size: 12pt;'><a href='"+ task_url +"'>"+obj.pending_task+"</a>, was assigned to " +obj.assigned_user+ " and has not been accepted. </span></p>");
	template.print("<p><span style='font-family: georgia, palatino; font-size: 12pt;'>The suspense date is "+obj.suspense_date+" </span></p>");

})(current,  template, email, email_action, event);
